 pub unsafe extern "C" fn _IO_file_open(
-    fp: *mut c_void,
+    _fp: *mut c_void,
     filename: *const c_char,
     posix_mode: c_int,
     prot: c_int,
-    read_write: c_int,
-    is32not64: c_int,
+    _read_write: c_int,
+    _is32not64: c_int,
